import React, { useState } from 'react';
import {
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  Grid,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  IconButton,
  Card,
  CardContent,
  Divider,
  Alert,
  CircularProgress,
} from '@mui/material';
import {
  Search,
  Person,
  AccountBalance,
  Print,
  Download,
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import { accountService } from '../../services/accountService';
import { customerService } from '../../services/customerService';
import CustomerSearch from '../customers/CustomerSearch';

const LedgerView = () => {
  const [customer, setCustomer] = useState(null);
  const [ledger, setLedger] = useState([]);
  const [loading, setLoading] = useState(false);
  const [customerSearchOpen, setCustomerSearchOpen] = useState(false);
  const [error, setError] = useState('');

  const handleCustomerSelect = async (selectedCustomer) => {
    setCustomer(selectedCustomer);
    await fetchLedger(selectedCustomer.id);
  };

  const fetchLedger = async (customerId) => {
    setLoading(true);
    try {
      const data = await accountService.getCustomerLedger(customerId);
      setLedger(data);
      setError('');
    } catch (error) {
      setError('Failed to fetch ledger details');
      toast.error('Failed to fetch ledger');
    } finally {
      setLoading(false);
    }
  };

  const getTransactionTypeColor = (type) => {
    const colors = {
      'Invoice': 'primary',
      'Cash Sale': 'info',
      'Credit Sale': 'primary',
      'Receipt': 'success',
      'Payment': 'warning',
      'Credit Note': 'error',
    };
    return colors[type] || 'default';
  };

  const getTransactionType = (entry) => {
    // Determine transaction type based on entry data
    if (entry.type === 'Invoice' && entry.paymentMode === 'CASH') {
      return 'Cash Sale';
    } else if (entry.type === 'Invoice' && entry.paymentMode === 'CREDIT') {
      return 'Credit Sale';
    } else if (entry.type === 'Invoice') {
      // If no payment mode, check if amount equals paid amount
      if (entry.amount === entry.paidAmount) {
        return 'Cash Sale';
      } else {
        return 'Credit Sale';
      }
    } else if (entry.type === 'Receipt') {
      return 'Receipt';
    } else if (entry.type === 'Payment') {
      return 'Payment';
    } else if (entry.type === 'Credit Note') {
      return 'Credit Note';
    }
    return entry.type || 'Transaction';
  };

  const isCashTransaction = (entry) => {
    // Check if transaction is cash (already paid)
    if (entry.type === 'Invoice' && entry.paymentMode === 'CASH') {
      return true;
    }
    if (entry.type === 'Invoice' && entry.amount === entry.paidAmount) {
      return true;
    }
    if (entry.type === 'Receipt') {
      return true; // Receipts are payments, not affecting balance in same way
    }
    return false;
  };

  const calculateTotals = () => {
    let totalDebit = 0;
    let totalCredit = 0;
    let runningBalance = 0;

    // Calculate running balance correctly - EXCLUDING CASH SALES
    const updatedLedger = ledger.map((entry) => {
      const amount = entry.amount || 0;
      const payment = entry.payment || 0;
      const paidAmount = entry.paidAmount || 0;
      const isCash = isCashTransaction(entry);
      
      let debitAmount = 0;
      let creditAmount = 0;
      let balanceChange = 0;

      // For credit invoices (customer owes us) - affects balance
      if (entry.type === 'Invoice' && !isCash) {
        // Only credit sales affect balance
        const outstanding = amount - paidAmount;
        if (outstanding > 0) {
          debitAmount = outstanding;
          balanceChange = outstanding;
          totalDebit += outstanding;
        }
      } 
      // For receipts (customer paid) - affects balance
      else if (entry.type === 'Receipt') {
        creditAmount = payment;
        balanceChange = -payment;
        totalCredit += payment;
      }
      // For payments (we paid customer) - affects balance
      else if (entry.type === 'Payment') {
        debitAmount = payment;
        balanceChange = payment;
        totalDebit += payment;
      }
      // For Credit Notes (we owe customer) - affects balance
      else if (entry.type === 'Credit Note') {
        creditAmount = amount;
        balanceChange = -amount;
        totalCredit += amount;
      }
      // Cash sales - no balance change (already paid)
      else if (entry.type === 'Invoice' && isCash) {
        // Cash sales don't affect balance
        debitAmount = amount;
        // Don't add to running balance
        // Just show for reference
      }
      
      // Update running balance only for credit transactions
      if (entry.type !== 'Invoice' || !isCash) {
        runningBalance += balanceChange;
      }

      // For display purposes, show full amount for cash sales but don't affect balance
      const displayDebit = (entry.type === 'Invoice') ? amount : (debitAmount > 0 ? debitAmount : 0);
      const displayCredit = (entry.type === 'Receipt') ? payment : (creditAmount > 0 ? creditAmount : 0);

      return {
        ...entry,
        debit: displayDebit,
        credit: displayCredit,
        balance: runningBalance,
        isCashTransaction: isCash,
        transactionType: getTransactionType(entry)
      };
    });

    return { 
      totalDebit, 
      totalCredit, 
      balance: runningBalance,
      updatedLedger 
    };
  };

  const totals = calculateTotals();
  const displayLedger = totals.updatedLedger || ledger;

  return (
    <Box>
      <Box display="flex" alignItems="center" gap={2} mb={3}>
        <AccountBalance sx={{ fontSize: 40, color: '#1976d2' }} />
        <Box>
          <Typography variant="h4" fontWeight="bold">
            Customer Ledger
          </Typography>
          <Typography variant="body2" color="textSecondary">
            View customer transaction history
          </Typography>
        </Box>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>
          {error}
        </Alert>
      )}

      <Grid container spacing={3}>
        <Grid item xs={12}>
          <Paper sx={{ p: 3, borderRadius: 2 }}>
            <Box display="flex" gap={2} mb={3} alignItems="center" flexWrap="wrap">
              <TextField
                label="Customer"
                value={customer?.name || ''}
                placeholder="Search customer..."
                sx={{ flexGrow: 1, minWidth: 200 }}
                InputProps={{
                  readOnly: true,
                  endAdornment: (
                    <IconButton onClick={() => setCustomerSearchOpen(true)}>
                      <Search />
                    </IconButton>
                  ),
                }}
              />
              {customer && (
                <Button
                  variant="outlined"
                  color="error"
                  onClick={() => {
                    setCustomer(null);
                    setLedger([]);
                  }}
                >
                  Clear
                </Button>
              )}
              {ledger.length > 0 && (
                <>
                  <Button
                    variant="outlined"
                    startIcon={<Print />}
                    onClick={() => window.print()}
                  >
                    Print
                  </Button>
                  <Button
                    variant="outlined"
                    startIcon={<Download />}
                  >
                    Export
                  </Button>
                </>
              )}
            </Box>

            {customer && (
              <Box mb={3}>
                <Grid container spacing={2}>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Customer Name
                        </Typography>
                        <Typography variant="h6">{customer.name}</Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Phone
                        </Typography>
                        <Typography variant="h6">{customer.phone}</Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Current Balance
                        </Typography>
                        <Typography variant="h6" color={totals.balance > 0 ? 'error' : totals.balance < 0 ? 'success' : 'textSecondary'}>
                          {totals.balance === 0 ? '₹0.00 (Settled)' : 
                            totals.balance > 0 ? `₹${totals.balance.toFixed(2)} (Receivable)` : 
                            `₹${Math.abs(totals.balance).toFixed(2)} (Payable)`}
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                </Grid>

                <Grid container spacing={2} mt={1}>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Total Sales
                        </Typography>
                        <Typography variant="h6" color="primary">
                          ₹{displayLedger.reduce((sum, entry) => {
                            if (entry.type === 'Invoice') return sum + (entry.amount || 0);
                            return sum;
                          }, 0).toFixed(2)}
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Total Payments Received
                        </Typography>
                        <Typography variant="h6" color="success">
                          ₹{displayLedger.reduce((sum, entry) => {
                            if (entry.type === 'Receipt') return sum + (entry.payment || 0);
                            return sum;
                          }, 0).toFixed(2)}
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                  <Grid item xs={12} md={4}>
                    <Card>
                      <CardContent>
                        <Typography variant="body2" color="textSecondary">
                          Outstanding Balance
                        </Typography>
                        <Typography variant="h6" color={totals.balance > 0 ? 'error' : 'success'}>
                          {totals.balance === 0 ? '₹0.00' : 
                            totals.balance > 0 ? `₹${totals.balance.toFixed(2)} (Due)` : 
                            `₹${Math.abs(totals.balance).toFixed(2)} (Credit)`}
                        </Typography>
                      </CardContent>
                    </Card>
                  </Grid>
                </Grid>
              </Box>
            )}

            {loading ? (
              <Box display="flex" justifyContent="center" py={4}>
                <CircularProgress />
              </Box>
            ) : displayLedger.length > 0 ? (
              <TableContainer>
                <Table>
                  <TableHead>
                    <TableRow sx={{ backgroundColor: '#f5f7fa' }}>
                      <TableCell>Date</TableCell>
                      <TableCell>Type</TableCell>
                      <TableCell>Invoice No</TableCell>
                      <TableCell>Description</TableCell>
                      <TableCell align="right">Amount</TableCell>
                      <TableCell align="right">Paid</TableCell>
                      <TableCell align="right">Balance</TableCell>
                      <TableCell>Status</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {displayLedger.map((entry, index) => {
                      const isCash = entry.isCashTransaction;
                      const amount = entry.amount || 0;
                      const paidAmount = entry.paidAmount || entry.payment || 0;
                      const outstanding = amount - paidAmount;
                      
                      return (
                        <TableRow key={index} sx={{ 
                          backgroundColor: isCash ? '#f5f5f5' : 'inherit',
                          opacity: isCash ? 0.8 : 1
                        }}>
                          <TableCell>
                            {entry.date ? new Date(entry.date).toLocaleDateString() : '-'}
                          </TableCell>
                          <TableCell>
                            <Chip
                              label={entry.transactionType || entry.type}
                              color={getTransactionTypeColor(entry.transactionType || entry.type)}
                              size="small"
                            />
                            {isCash && (
                              <Chip
                                label="Paid"
                                color="success"
                                size="small"
                                sx={{ ml: 1 }}
                              />
                            )}
                          </TableCell>
                          <TableCell>{entry.invoiceNo || '-'}</TableCell>
                          <TableCell>
                            {entry.description || entry.remarks || (entry.type === 'Invoice' ? 'Sale' : '') || '-'}
                          </TableCell>
                          <TableCell align="right">
                            {amount > 0 ? `₹${amount.toFixed(2)}` : '-'}
                          </TableCell>
                          <TableCell align="right">
                            {paidAmount > 0 ? `₹${paidAmount.toFixed(2)}` : '-'}
                          </TableCell>
                          <TableCell align="right">
                            <Typography
                              fontWeight={500}
                              color={outstanding > 0 ? 'error' : outstanding < 0 ? 'success' : 'textSecondary'}
                            >
                              {outstanding === 0 ? '₹0.00' : 
                                outstanding > 0 ? `₹${outstanding.toFixed(2)}` : 
                                `(${Math.abs(outstanding).toFixed(2)})`}
                            </Typography>
                          </TableCell>
                          <TableCell>
                            <Chip
                              label={outstanding === 0 ? 'Settled' : outstanding > 0 ? 'Due' : 'Credit'}
                              color={outstanding === 0 ? 'success' : outstanding > 0 ? 'warning' : 'info'}
                              size="small"
                            />
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
              </TableContainer>
            ) : customer ? (
              <Box textAlign="center" py={4}>
                <Typography color="textSecondary">
                  No transactions found for this customer
                </Typography>
              </Box>
            ) : (
              <Box textAlign="center" py={4}>
                <Typography color="textSecondary">
                  Search and select a customer to view ledger
                </Typography>
              </Box>
            )}
          </Paper>
        </Grid>
      </Grid>

      <CustomerSearch
        open={customerSearchOpen}
        onClose={() => setCustomerSearchOpen(false)}
        onSelect={handleCustomerSelect}
      />
    </Box>
  );
};

export default LedgerView;
